package main

import (
	"fmt"
	"log"
	"net/http"
	"strings"
)

type User struct {
	Username string
	Role     string
}

var allowedRoles = map[string]bool{
	"admin": true,
	"mod":   true,
}

func main() {
	http.HandleFunc("/chat", chatHandler)
	log.Fatal(http.ListenAndServe(":8080", nil))
}

func chatHandler(w http.ResponseWriter, r *http.Request) {
	username := r.Header.Get("X-Username")
	role := r.Header.Get("X-Role")

	if !allowedRoles[role] {
		http.Error(w, "Unauthorized", http.StatusUnauthorized)
		return
	}

	user := User{Username: username, Role: role}
	message := r.URL.Query().Get("message")

	if strings.HasPrefix(message, "/") {
		handleCommand(user, message)
	} else {
		fmt.Fprintf(w, "Message received: %s", message)
	}
}

func handleCommand(user User, message string) {
	parts := strings.Fields(message)
	command := parts[0]

	switch command {
	case "/kick":
		if user.Role == "admin" || user.Role == "mod" {
			target := parts[1]
			fmt.Printf("User %s kicked by %s\n", target, user.Username)
		} else {
			fmt.Println("Unauthorized command attempt")
		}
	case "/ban":
		if user.Role == "admin" {
			target := parts[1]
			fmt.Printf("User %s banned by %s\n", target, user.Username)
		} else {
			fmt.Println("Unauthorized command attempt")
		}
	case "/giveitems":
		if user.Role == "admin" {
			target := parts[1]
			item := parts[2]
			fmt.Printf("User %s given item %s by %s\n", target, item, user.Username)
		} else {
			fmt.Println("Unauthorized command attempt")
		}
	default:
		fmt.Println("Unknown command")
	}
}